import{_ as a,o as r,c as o,a2 as t}from"./chunks/framework.Uc-laZr6.js";const u=JSON.parse('{"title":"Colección de Anti-Patrones de RxJS","description":"Una guía práctica para comprender los anti-patrones de RxJS y escribir código más robusto y mantenible. Explicaremos 16 errores comunes y cómo tratarlos, incluyendo el mal uso de Subject, subscribe anidados, ramificación condicional en subscribe, fugas de memoria y mal uso de shareReplay.","frontmatter":{"description":"Una guía práctica para comprender los anti-patrones de RxJS y escribir código más robusto y mantenible. Explicaremos 16 errores comunes y cómo tratarlos, incluyendo el mal uso de Subject, subscribe anidados, ramificación condicional en subscribe, fugas de memoria y mal uso de shareReplay."},"headers":[],"relativePath":"es/guide/anti-patterns/index.md","filePath":"es/guide/anti-patterns/index.md","lastUpdated":1765383284000}'),s={name:"es/guide/anti-patterns/index.md"};function i(d,e,n,c,l,m){return r(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="coleccion-de-anti-patrones-de-rxjs" tabindex="-1">Colección de Anti-Patrones de RxJS <a class="header-anchor" href="#coleccion-de-anti-patrones-de-rxjs" aria-label="Permalink to &quot;Colección de Anti-Patrones de RxJS&quot;">​</a></h1><p>RxJS es una poderosa biblioteca de programación reactiva, pero cuando se usa incorrectamente, puede ser un caldo de cultivo para errores y mantenibilidad reducida. En esta sección, presentaremos algunos errores comunes al usar RxJS con TypeScript y las mejores prácticas para evitarlos.</p><h2 id="proposito-de-esta-seccion" tabindex="-1">Propósito de esta sección <a class="header-anchor" href="#proposito-de-esta-seccion" aria-label="Permalink to &quot;Propósito de esta sección&quot;">​</a></h2><ul><li><strong>Prevenir errores</strong>: evitar problemas de implementación comprendiendo los errores comunes antes de que ocurran</li><li><strong>Mejorar la Mantenibilidad</strong>: aprender patrones de código que sean fáciles de leer y probar</li><li><strong>Optimizar el rendimiento</strong>: aprender técnicas para evitar fugas de memoria y procesamiento innecesario</li></ul><h2 id="lista-de-anti-patrones" tabindex="-1">Lista de anti-patrones <a class="header-anchor" href="#lista-de-anti-patrones" aria-label="Permalink to &quot;Lista de anti-patrones&quot;">​</a></h2><p>Esta sección cubre los siguientes 17 anti-patrones.</p><h3 id="🔴-problemas-criticos" tabindex="-1">🔴 Problemas Críticos <a class="header-anchor" href="#🔴-problemas-criticos" aria-label="Permalink to &quot;🔴 Problemas Críticos&quot;">​</a></h3><p>Estos patrones pueden tener un impacto grave en su aplicación.</p><table tabindex="0"><thead><tr><th>Patrón</th><th>Problema</th><th>Impacto</th></tr></thead><tbody><tr><td><strong><a href="./common-mistakes#1-publicacion-externa-de-subject">Publicación externa de Subject</a></strong></td><td>Publicar el Subject tal cual, y hacer posible llamar <code>next()</code> desde el exterior</td><td>Imprevisibilidad de la gestión del estado, difícil de depurar</td></tr><tr><td><strong><a href="./common-mistakes#2-subscribe-anidado-callback-hell">Subscribe anidado</a></strong></td><td>Llamar más <code>subscribe</code> en <code>subscribe</code></td><td>Callback hell, complicación del manejo de errores</td></tr><tr><td><strong><a href="./flag-management">Proliferación desenfrenada de flags de gestión de estado</a></strong></td><td>Gestión del estado con 17 flags booleanos, el pensamiento imperativo aún permanece</td><td>Baja legibilidad, difícil de mantener, semillero de errores</td></tr><tr><td><strong><a href="./subscribe-if-hell">Anidamiento de sentencias if en subscribe</a></strong></td><td>Ramificación condicional compleja (anidamiento de 3 o más niveles) en <code>subscribe</code></td><td>Baja legibilidad, difícil de probar, viola la filosofía declarativa</td></tr><tr><td><strong><a href="./common-mistakes#3-olvido-de-unsubscribe-fuga-de-memoria">Olvido de unsubscribe</a></strong></td><td>No cancelar la suscripción a streams infinitos</td><td>Fuga de memoria, desperdicio de recursos</td></tr><tr><td><strong><a href="./common-mistakes#4-mal-uso-de-sharereplay">Mal uso de shareReplay</a></strong></td><td>Usar sin comprender cómo funciona <code>shareReplay</code></td><td>Referencias a datos antiguos, fugas de memoria</td></tr></tbody></table><h3 id="🟡-problemas-que-requieren-atencion" tabindex="-1">🟡 Problemas que Requieren Atención <a class="header-anchor" href="#🟡-problemas-que-requieren-atencion" aria-label="Permalink to &quot;🟡 Problemas que Requieren Atención&quot;">​</a></h3><p>Estos pueden ser problemas en ciertas situaciones.</p><table tabindex="0"><thead><tr><th>Patrón</th><th>Problema</th><th>Impacto</th></tr></thead><tbody><tr><td><strong><a href="./common-mistakes#5-efectos-secundarios-en-map">Efectos secundarios en map</a></strong></td><td>Cambiar el estado en el operador <code>map</code></td><td>Comportamiento impredecible, difícil de probar</td></tr><tr><td><strong><a href="./common-mistakes#6-ignorar-diferencias-entre-observable-cold-hot">Ignorar Cold/Hot</a></strong></td><td>No considerar la naturaleza del Observable</td><td>Ejecución duplicada, comportamiento inesperado</td></tr><tr><td><strong><a href="./promise-observable-mixing">Mezcla con Promise</a></strong></td><td>No convertir Promise y Observable correctamente</td><td>No cancelable, mal manejo de errores</td></tr><tr><td><strong><a href="./common-mistakes#8-ignorar-backpressure">Ignorar backpressure</a></strong></td><td>No controlar eventos de alta frecuencia</td><td>Degradación del rendimiento, congelamiento de la UI</td></tr></tbody></table><h3 id="🔵-problemas-de-calidad-del-codigo" tabindex="-1">🔵 Problemas de Calidad del Código <a class="header-anchor" href="#🔵-problemas-de-calidad-del-codigo" aria-label="Permalink to &quot;🔵 Problemas de Calidad del Código&quot;">​</a></h3><p>Estos no son errores directos, pero son factores que reducen la calidad del código.</p><table tabindex="0"><thead><tr><th>Patrón</th><th>Problema</th><th>Impacto</th></tr></thead><tbody><tr><td><strong><a href="./common-mistakes#9-supresion-de-errores">Supresión de errores</a></strong></td><td>No manejar los errores correctamente</td><td>Dificultades de depuración, mala experiencia del usuario</td></tr><tr><td><strong><a href="./common-mistakes#10-fugas-de-suscripcion-de-eventos-dom">Fugas de eventos DOM</a></strong></td><td>No liberar los event listeners del DOM</td><td>Fugas de memoria, degradación del rendimiento</td></tr><tr><td><strong><a href="./common-mistakes#11-falta-de-seguridad-de-tipos-uso-excesivo-de-any">Falta de seguridad de tipos</a></strong></td><td>Uso excesivo de <code>any</code></td><td>Errores en tiempo de ejecución, dificultades de refactorización</td></tr><tr><td><strong><a href="./common-mistakes#12-seleccion-impropia-de-operadores">Selección impropia de operadores</a></strong></td><td>Uso de operadores que no sirven al propósito</td><td>Ineficiencia, comportamiento inesperado</td></tr><tr><td><strong><a href="./common-mistakes#13-sobrecomplicacion">Sobrecomplicación</a></strong></td><td>Complicar un proceso que puede escribirse de forma simple</td><td>Baja legibilidad, difícil de mantener</td></tr><tr><td><strong><a href="./one-liner-hell">Infierno de one-liner</a></strong></td><td>Definiciones de streams, conversiones y suscripciones mezcladas</td><td>Difícil de depurar, difícil de probar, baja legibilidad</td></tr><tr><td><strong><a href="./common-mistakes#14-cambios-de-estado-en-subscribe">Cambios de estado en subscribe</a></strong></td><td>Cambio de estado directamente en <code>subscribe</code></td><td>Difícil de probar, causa errores</td></tr><tr><td><strong><a href="./common-mistakes#15-falta-de-pruebas">Falta de pruebas</a></strong></td><td>No hay pruebas escritas para el código RxJS</td><td>Regresión, dificultades de refactorización</td></tr></tbody></table><h2 id="como-proceder-con-el-estudio" tabindex="-1">Cómo proceder con el estudio <a class="header-anchor" href="#como-proceder-con-el-estudio" aria-label="Permalink to &quot;Cómo proceder con el estudio&quot;">​</a></h2><ol><li>Aprender 15 anti-patrones en detalle en <strong><a href="./common-mistakes">Errores Comunes y Cómo Corregirlos</a></strong></li><li>Cada anti-patrón tiene un &quot;ejemplo malo&quot; y un &quot;ejemplo bueno&quot; de código</li><li>Revisar su código con <strong><a href="./checklist">Lista de Verificación para Evitar Anti-patrones</a></strong></li><li>Practicar las mejores prácticas y compartirlas con su equipo</li></ol><h2 id="secciones-relacionadas" tabindex="-1">Secciones Relacionadas <a class="header-anchor" href="#secciones-relacionadas" aria-label="Permalink to &quot;Secciones Relacionadas&quot;">​</a></h2><p>Después de aprender sobre anti-patrones, consulte también las siguientes secciones.</p><ul><li><strong><a href="/RxJS-with-TypeScript/es/guide/error-handling/strategies">Manejo de Errores</a></strong> - Estrategias apropiadas de manejo de errores</li><li><strong><a href="/RxJS-with-TypeScript/es/guide/testing/unit-tests">Técnicas de Prueba</a></strong> - Cómo probar el código RxJS</li><li><strong><a href="/RxJS-with-TypeScript/es/guide/operators/">Comprensión de Operadores</a></strong> - Cómo elegir los operadores adecuados</li></ul><h2 id="proximos-pasos" tabindex="-1">Próximos Pasos <a class="header-anchor" href="#proximos-pasos" aria-label="Permalink to &quot;Próximos Pasos&quot;">​</a></h2><ol><li>Comience con <strong><a href="./common-mistakes">Errores Comunes y Cómo Corregirlos</a></strong> para aprender anti-patrones prácticos y sus soluciones.</li><li>Después de aprender, revise su código real con la <strong><a href="./checklist">Lista de Verificación para Evitar Anti-patrones</a></strong>.</li></ol><hr><p><strong>IMPORTANTE</strong>: Estos anti-patrones se encuentran frecuentemente en proyectos reales. Comprenderlos tempranamente le ayudará a escribir código RxJS de calidad.</p>',24)])])}const b=a(s,[["render",i]]);export{u as __pageData,b as default};
